<template>
	<view class="page">
		<u-navbar :is-back="true" :background="{backgroundColor:'rgba(255,255,255,0)' }" immersive
			:border-bottom="false" />
		<view class="swiper-box">
			<u-swiper :list="list" :effect3d="true" :autoplay="false" height="888" effect3d-previous-margin="170"
				mode="none" border-radius="20" bg-color="#FAFAFA" img-mode="scaleToFill"
				@change="swiperChange"></u-swiper>
		</view>
		<view class="link-box" @click="copyLink">
			<text class="label">专属链接：</text>
			<view class="link line1">{{shareLink}}</view>
			<view class="copy">
				<u-icon name="zhuanfa" color="#9b9fa8"></u-icon>
			</view>
		</view>
		<view class="footer-box">
			<view class="share-list">
				<view class="share-item" @click="shareItemClick(1)">
					<u-image :src="$util.img('/statics/invite/icon_share_1.svg')" height="50" width="50" />
					<text>分享到微信</text>
				</view>
				<view class="share-item" @click="shareItemClick(2)">
					<u-image :src="$util.img('/statics/invite/icon_share_2.svg')" height="50" width="50" />
					<text>分享到QQ</text>
				</view>
				<view class="share-item" @click="shareItemClick(3)">
					<u-image :src="$util.img('/statics/invite/icon_share_3.svg')" height="50" width="50" />
					<text>嵌入公众号</text>
				</view>
				<view class="share-item" @click="shareItemClick(4)">
					<u-image :src="$util.img('/statics/invite/icon_share_4.svg')" height="50" width="50" />
					<text>店铺专属码</text>
				</view>
			</view>
			<view class="btn" @click="shareItemClick(5)">生成专属海报</view>
		</view>
		<InviteShare :show.sync="shareShow" :shareLink="wxgzhUrl" :bgImg="shareBgImg" />
		<Official :show.sync="officialShow" :shareLink="wxgzhUrl" appid="xxxxxxxxxxxxxx" />
		<Qrcode :show.sync="qrcodeShow" :shareLink="shareLink" />
	</view>
</template>

<script>
	import config from '@/common/config.js'
	import InviteShare from './components/InviteShare'
	import Official from './components/InviteShare/official'
	import Qrcode from './components/InviteShare/qrcode'
	// import StatusBar from '@/components/my-page-header/status-bar'

	export default {
		components: {
			InviteShare,
			Official,
			Qrcode,
			// StatusBar
		},

		data() {
			return {
				list: [
					// {
					// 	image: this.$util.img('/statics/invite/poster-1.png'),
					// },
					// {
					// 	image: this.$util.img('/statics/invite/poster-3.png'),
					// },
					// {
					// 	image: this.$util.img('/statics/invite/poster-4.png'),
					// },
					// {
					// 	image: this.$util.img('/statics/invite/poster-5.png'),
					// },
					// {
					// 	image: this.$util.img('/statics/invite/poster-6.png'),
					// },
					// {
					// 	image: this.$util.img('/statics/invite/poster-7.png'),
					// },
					// {
					// 	image: this.$util.img('/statics/invite/poster-8.png'),
					// },
					// {
					// 	image: this.$util.img('/statics/invite/poster-9.png'),
					// },
					// {
					// 	image: this.$util.img('/statics/invite/poster-10.png'),
					// },
				],
				index: 0,
				shareShow: false,
				officialShow: false,
				qrcodeShow: false,

				wxgzhUrl: '',
			}
		},
		computed: {
			shareLink() {
				return `${config.cdnurl}/?pid=${this.userinfo.id}`
			},
			shareBgImg() {
				return this.$_.get(this.list, `${this.index}.image`, '')
			},
		},
		onLoad() {
			this.fetchData()
		},
		onShow() {

		},
		methods: {
			async fetchData() {
				const {
					share_images
				} = await this.$u.api.sharePosters()
				this.list = share_images.map(item => {
					return {
						image: this.$util.img(item)
					}
				})
				const {
					url
				} = await this.$u.api.getwxgzhqrcode({
					type: 2
				})
				this.wxgzhUrl = url
			},
			copyLink() {
				uni.setClipboardData({
					data: this.shareLink,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			shareItemClick(type) {
				if (type == 1 || type == 2 || type == 5) {
					this.shareShow = true
				} else if (type == 3) {
					this.officialShow = true
				} else if (type == 4) {
					this.qrcodeShow = true
				}
			},
			swiperChange(e) {
				this.index = e
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.page {
		display: flex;
		flex-direction: column;
		align-items: center;
		gap: 20rpx;
		touch-action: manipulation;
		background-color: #FAFAFA;

		.swiper-box {
			flex: 1;
			width: 100%;
			padding-top: 20rpx;
			display: flex;
			flex-direction: column;
			justify-content: center;
		}

		.link-box {
			width: calc(100% - 40rpx);
			background-color: #fff;
			height: 80rpx;
			display: flex;
			align-items: center;
			border-radius: 10rpx;
			padding: 0 20rpx;

			.link {
				flex: 1;
			}

			.copy {
				border-left: 2rpx solid #C2C2C2;
				padding: 0 20rpx;
			}

			&:active {
				background-color: #f1f1f1;
			}
		}

		.footer-box {
			width: 100%;
			background-color: #fff;
			border-radius: 30rpx 30rpx 0 0;
			padding: 20rpx;
			display: flex;
			flex-direction: column;
			gap: 20rpx;

			.share-list {
				width: 100%;
				display: flex;
				align-items: center;
				justify-content: space-around;

				.share-item {
					background-color: #f6f6f6;
					display: flex;
					flex-direction: column;
					align-items: center;
					justify-content: center;
					gap: 20rpx;
					height: 150rpx;
					width: 150rpx;
					border-radius: 10rpx;
					padding: 10rpx;
					font-size: 22rpx;

					&:active {
						background-color: #ddd;
					}
				}
			}

			.btn {
				width: 100%;
				height: 80rpx;
				display: flex;
				align-items: center;
				justify-content: center;
				background-color: #ff5f01;
				border-radius: 10rpx;
				color: #fff;
			}
		}
	}
</style>