<template>
	<u-popup v-model="popupShow" mode="center" width="80%" @close="close" @open="open">
		<image :src="path" class="poster-img" @longtap="savePosterPath(path)" :fade="false" />
		<l-painter isCanvasToTempFilePath @success="path = $event" custom-style="position: fixed; left: 200%">
			<l-painter-view>
				<l-painter-view css="width: 100%;height:1100rpx;">
					<l-painter-image :src="bgImgBase64" css="width: 100%;height:100%; object-fit: cover;" />
				</l-painter-view>
				<l-painter-view css="background: #fff; height: 172rpx;position:relative;padding:0 30rpx;">
					<l-painter-view css="margin-top:40rpx;display:inline-block">
						<l-painter-text text="活动详情>>>"
							css="color: #333; font-size: 28rpx; fontWeight: bold;display:block; margin-bottom:20rpx;" />
						<l-painter-text text="扫码右侧二维码,直达活动首页" css="color: #BEBEBE; font-size: 24rpx;display:block;" />
					</l-painter-view>
					<l-painter-view
						css="position:absolute;right:20rpx;top:14rpx;border:1px solid #BEBEBE;padding:10rpx;">
						<l-painter-qrcode css="width: 120rpx; height: 120rpx;" :text="shareLink"></l-painter-qrcode>
					</l-painter-view>
				</l-painter-view>
			</l-painter-view>
		</l-painter>
		<view class="tip" @click="popupShow=false">长按保存为海报或转发</view>
	</u-popup>
</template>

<script>
	export default {
		components: {

		},
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			shareLink: {
				type: String,
				default: '',
			},
			bgImg: {
				type: String,
				default: '',
			}
		},
		data() {
			return {
				popupShow: false,
				bgImgBase64: '',
				cacheList: {},
				path: '',
			}
		},
		watch: {
			show(nv) {
				this.popupShow = nv
			}
		},
		options: {
			styleIsolation: 'shared'
		},
		mounted() {
			this.open()
		},
		methods: {
			async open() {
				if (Reflect.has(this.cacheList, this.bgImg)) {
					this.bgImgBase64 = this.cacheList[this.bgImg]
				} else {
					const res = await this.pathToBase64(this.bgImg)
					this.bgImgBase64 = res
					this.cacheList[this.bgImg] = res
				}
			},
			close() {
				this.path = ''
				this.bgImgBase64 = ''
				this.$emit("update:show", false)
			},
			async pathToBase64(path) {
				return new Promise(async (resovle, rejct) => {
					// #ifdef H5
					const canvas = document.createElement('canvas')
					const canvasContext = canvas.getContext('2d')
					var img = new Image()
					img.crossOrigin = "anonymous"
					img.src = path
					img.onload = function() {
						canvas.width = img.width
						canvas.height = img.height
						canvasContext.drawImage(img, 0, 0)
						const base64Data = canvas.toDataURL('image/png')
						resovle(base64Data)
					}
					img.onerror = async () => {
						//获取失败了就请求接口
						const {
							base64,
						} = await this.$u.api.download({
							type: 2,
							url: path
						})
						if (base64) {
							const base64Data = 'data:image/png;base64,' + base64
							resovle(base64Data)
						} else {
							rejct('转换base64失败')
						}
					}
					// #endif
					// #ifndef H5
					//获取失败了就请求接口
					const {
						base64,
					} = await this.$u.api.download({
						type: 2,
						url: path
					})
					if (base64) {
						const base64Data = 'data:image/png;base64,' + base64
						resovle(base64Data)
					} else {
						rejct('转换base64失败')
					}
					// #endif
				})
			},
			savePosterPath(path) {
				//#ifdef APP
				uni.showLoading({
					mask: true,
					title: '保存中...',

				})
				uni.saveImageToPhotosAlbum({
					filePath: path,
					success: (res) => {
						uni.hideLoading()
						this.$util.msg('图片已保存:' + res.path)
					},
					fail: (err) => {
						uni.hideLoading()
						this.$util.msg('图片保存失败')
					}
				})
				//#endif
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.u-mode-center-box {
			background-color: transparent !important;
		}

		.poster-img>img {
			-webkit-touch-callout: default !important;
		}
	}

	.poster-img {
		width: 100%;
		height: 1100rpx;
	}

	.tip {
		background-color: #ff5f01;
		color: #fff;
		width: 100%;
		height: 84rpx;
		display: flex;
		align-items: center;
		justify-content: center;
		border-radius: 6rpx;
		position: relative;
		margin-top: 20rpx;

		&::before {
			content: "";
			position: absolute;
			border-width: 10rpx;
			border-style: solid;
			border-color: transparent;
			border-bottom-color: #ff5f01;
			top: -20rpx;
		}
	}
</style>