<template>
	<u-popup v-model="popupShow" mode="bottom" width="80%" :border-radius="20" @close="close" @open="open">
		<view class="popup-content">
			<view class="title">嵌入公众号</view>
			<view class="choose-bar" @click="copyLink">
				<view class="name">店铺专属路径</view>
				<view class="tips">{{shareLink}}</view>
				<view class="copy">
					<u-icon name="zhuanfa" color="#9b9fa8"></u-icon>
				</view>
			</view>
			<view class="choose-bar" @click="copyAppid">
				<view class="name">小程序APPID</view>
				<view class="tips">{{appid}}</view>
				<view class="copy">
					<u-icon name="zhuanfa" color="#9b9fa8"></u-icon>
				</view>
			</view>
			<view class="hr">使用场景</view>
			<view class="text-bar">
				<view class="label">
					<u-icon name="file-text-fill"></u-icon>
					<text class="t1">将你店铺嵌入：</text>
					<text class="t2">公众号文章</text>
				</view>
				<u-icon name="arrow-right"></u-icon>
			</view>
			<view class="text-bar">
				<view class="label">
					<u-icon name="list"></u-icon>
					<text class="t1">将你店铺嵌入：</text>
					<text class="t2">公众号菜单栏</text>
				</view>
				<u-icon name="arrow-right"></u-icon>
			</view>
		</view>
	</u-popup>
</template>

<script>
	export default {
		components: {

		},
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			shareLink: {
				type: String,
				default: '',
			},
			appid: {
				type: String,
				default: '',
			}
		},
		data() {
			return {
				popupShow: false,
			}
		},
		watch: {
			show(nv) {
				this.popupShow = nv
			}
		},
		options: {
			styleIsolation: 'shared'
		},
		mounted() {

		},
		methods: {
			async open() {

			},
			close() {
				this.$emit("update:show", false)
			},
			copyLink() {
				uni.setClipboardData({
					data: this.shareLink,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			copyAppid() {
				uni.setClipboardData({
					data: this.appid,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	// ::v-deep {
	// 	.u-mode-center-box {
	// 		background-color: transparent !important;
	// 	}
	// }

	.popup-content {
		width: 100%;
		display: flex;
		flex-direction: column;
		padding: 20rpx;
		gap: 20rpx;

		.title {
			margin-top: 10rpx;
			width: 100%;
			display: flex;
			align-items: center;
			justify-content: center;
			font-size: 32rpx;
			font-weight: 700;
			position: relative;
		}

		.choose-bar {
			width: 100%;
			height: 120rpx;
			display: flex;
			flex-direction: column;
			position: relative;
			justify-content: center;
			background-color: #f2f2f2;
			border-radius: 10rpx;
			padding: 20rpx;
			gap: 10rpx;

			&:active {
				background-color: #c2c2c2
			}

			.name {
				font-size: 30rpx;
				font-weight: bold;
				display: flex;
				align-items: center;
				gap: 10rpx;

				&::before {
					content: "";
					display: inline-block;
					width: 10rpx;
					height: 30rpx;
					border-radius: 10rpx;
					background-color: #ff5f01;
				}
			}

			.tips {
				color: #999;
				font-size: 20rpx;
			}

			.copy {
				position: absolute;
				top: 50%;
				right: 20rpx;
				transform: translateY(-50%);
				width: 70rpx;
				height: 70rpx;
				display: flex;
				align-items: center;
				justify-content: center;
				background-color: #fff;
				border-radius: 10rpx;
			}
		}

		.hr {
			display: flex;
			align-items: center;
			justify-content: center;
			height: 60rpx;
			width: 100%;
			gap: 20rpx;
			font-weight: 700;

			&::before {
				content: "";
				flex: 1;
				height: 0;
				border-bottom: 1px solid rgba(0, 0, 0, .1);
			}

			&::after {
				content: "";
				flex: 1;
				height: 0;
				border-bottom: 1px solid rgba(0, 0, 0, .1);
			}
		}

		.text-bar {
			background-color: #f2f2f2;
			width: 100%;
			height: 80rpx;
			border-radius: 20rpx;
			padding: 0 20rpx;
			display: flex;
			align-items: center;
			justify-content: space-between;

			&:active {
				background-color: #c2c2c2
			}

			.t1 {
				color: #999;
				font-size: 28rpx;
				margin-left: 20rpx;
			}

			.t2 {
				font-weight: 700;
				color: #333;
			}
		}
	}
</style>