<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" width="80%" :border-radius="20" :z-index="998" @close="close"
			@open="open">
			<view class="popup-content">
				<view class="title">专属二维码</view>
				<view class="qrcode-list">
					<view class="qrcode-item" :class="{active:curr ==index}" v-for="item,index in qrcodeList"
						:key="index" @click="curr = index">
						<view class="check-right-box">
							<u-icon name="checkmark"></u-icon>
						</view>
						<view class="image" :style="item.style">
							<uqrcode :ref="`uqrcode-${index}`" :canvas-id="`qrcode-${index}`" :value="shareLink"
								size="430" :auto="false" :options="{
									areaColor:item.areaColor,
									backgroundColor:item.backgroundColor,
									margin:item.margin
								}" hide @complete="uqrcodeComplete(index,$event)">
							</uqrcode>
							<u-image :src="item.base64" v-if="item.base64" width="80%" height="80%" />
						</view>
						<view class="footer">{{item.name}}</view>
					</view>
				</view>
				<view class="btn" @click="showQrcode">生成专属二维码</view>
			</view>
		</u-popup>
		<DownloadImgBox :show.sync="downloadShow" :path="path" />
	</view>
</template>

<script>
	import DownloadImgBox from './download-img-box'
	export default {
		components: {
			DownloadImgBox
		},
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			shareLink: {
				type: String,
				default: '',
			},
		},
		data() {
			return {
				popupShow: false,
				curr: 0,
				qrcodeList: [{
					name: '白色背景',
					base64: '',
					areaColor: '#FFFFFF',
					backgroundColor: 'rgba(255,255,255,0)',
					margin: 20,
					style: {},
				}, {
					name: '透明背景',
					base64: '',
					areaColor: 'rgba(255,255,255,0)',
					backgroundColor: 'rgba(255,255,255,0)',
					margin: 20,
					style: {
						backgroundImage: `url(${this.$util.img('/statics/invite/transparent.png')})`,
						backgroundSize: '30px'
					}
				}],

				downloadShow: false,
			}
		},
		computed: {
			path() {
				return this.qrcodeList[this.curr].base64
			}
		},
		watch: {
			show(nv) {
				this.popupShow = nv
			}
		},
		options: {
			styleIsolation: 'shared'
		},
		mounted() {

		},
		methods: {
			async open() {

			},
			close() {
				this.$emit("update:show", false)
			},
			showQrcode() {
				this.downloadShow = true
			},
			uqrcodeComplete(index) {
				const key = 'uqrcode-' + index
				this.$refs[key][0].toTempFilePath({
					success: res => {
						this.qrcodeList[index].base64 = res.tempFilePath
					}
				})
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	// ::v-deep {
	// 	.u-mode-center-box {
	// 		background-color: transparent !important;
	// 	}
	// }

	.popup-content {
		width: 100%;
		display: flex;
		flex-direction: column;
		padding: 20rpx;
		gap: 20rpx;

		.title {
			margin-top: 10rpx;
			width: 100%;
			display: flex;
			align-items: center;
			justify-content: center;
			font-size: 32rpx;
			font-weight: 700;
			position: relative;
		}

		.qrcode-list {
			height: 412rpx;
			display: flex;
			align-items: center;
			width: 100%;
			gap: 10rpx;

			.qrcode-item {
				width: 340rpx;
				height: 410rpx;
				border-radius: 20rpx;
				border: 4px #f2f2f2 solid;
				display: flex;
				flex-direction: column;
				align-items: center;
				position: relative;
				overflow: hidden;

				.check-right-box {
					width: 40rpx;
					height: 40rpx;
					display: none;
					align-items: center;
					justify-content: center;
					border-radius: 50%;
					color: #fff;
					background-color: #ff5f01;
					position: absolute;
					right: 10rpx;
					top: 10rpx;
				}

				.image {
					width: 340rpx;
					height: 320rpx;
					display: flex;
					align-items: center;
					justify-content: center;
				}

				.footer {
					width: 100%;
					display: flex;
					align-items: center;
					justify-content: center;
					height: 75rpx;
					background-color: #f2f2f2;
					color: #999;
					font-size: 28rpx;
					font-weight: 500;
				}
			}

			.active {
				border: 4px #ff5f01 solid;

				.check-right-box {
					display: flex;
					z-index: 2;
				}

				.footer {
					color: #ff5f01;
					background-color: rgba(255, 95, 1, .1);
				}
			}
		}

		.btn {
			width: 100%;
			height: 80rpx;
			display: flex;
			align-items: center;
			justify-content: center;
			background-color: #ff5f01;
			border-radius: 10rpx;
			color: #fff;
			margin-bottom: 10rpx;
		}
	}
</style>