<template>
	<u-popup v-model="popupShow" mode="center" width="80%" @close="close" @open="open">
		<view class="image-box" :style="{
						backgroundImage: `url(${this.$util.img('/statics/invite/transparent.png')})`,
						backgroundSize: '30px'
					}">
			<u-image :src="path" mode="widthFix" @longpress="savePosterPath(path)" :fade="false" />
		</view>
		<view class="tip" @click="popupShow=false">长按保存为海报或转发</view>
	</u-popup>
</template>

<script>
	export default {
		components: {

		},
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			path: {
				type: String,
				default: '',
			},
			tip: {
				type: String,
				default: '',
			}
		},
		data() {
			return {
				popupShow: false,
			}
		},
		watch: {
			show(nv) {
				this.popupShow = nv
			}
		},
		options: {
			styleIsolation: 'shared'
		},
		mounted() {

		},
		methods: {
			async open() {

			},
			close() {
				this.$emit("update:show", false)
			},
			savePosterPath(path) {
				//#ifndef H5
				uni.showLoading({
					mask: true,
					title: '保存中...',

				})
				uni.saveImageToPhotosAlbum({
					filePath: path,
					success: (res) => {
						uni.hideLoading()
						this.$util.msg('图片已保存')
					},
					fail: (err) => {
						uni.hideLoading()
						this.$util.msg('图片保存失败')
					}
				})
				//#endif
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.u-mode-center-box {
			background-color: transparent !important;
		}
	}

	.tip {
		background-color: #ff5f01;
		color: #fff;
		width: 100%;
		height: 84rpx;
		display: flex;
		align-items: center;
		justify-content: center;
		border-radius: 6rpx;
		position: relative;
		margin-top: 20rpx;

		&::before {
			content: "";
			position: absolute;
			border-width: 10rpx;
			border-style: solid;
			border-color: transparent;
			border-bottom-color: #ff5f01;
			top: -20rpx;
		}
	}
</style>